import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false); // Add a loading state for better UX
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true); // Start loading
    try {
      // ✅ STEP 1: Connect to your backend login API (e.g., /api/users/login)
      const res = await axios.post("http://localhost:5000/api/users/login", { email, password });
      
      // ✅ STEP 2: Save Token and dynamic User Name to LocalStorage
      // Use "Guest" or "Mohana Priya" as Fallback if backend doesn't send name
      localStorage.setItem("token", res.data.token);
      localStorage.setItem("userName", res.data.name || "Guest");
      
      alert("Login Successful! Welcome to Truck Board Pro.");
      navigate('/marketplace'); // Redirect to Marketplace Dashboard
    } catch (err) {
      console.error(err);
      alert("Invalid Email or Password. Please try again.");
    } finally {
      setLoading(false); // Stop loading regardless of success/failure
    }
  };

  return (
    // Update the layout to a flexbox with two columns for left and right content
    <div className="min-h-screen flex items-center justify-center bg-[#FFFBEB] font-sans text-slate-900 px-4 py-8">
      
      {/* UPDATE: Full-screen container with two columns */}
      <div className="w-full max-w-[1200px] flex flex-col md:flex-row bg-white rounded-[3rem] shadow-2xl overflow-hidden border border-slate-100">
        
        {/* --- UPDATE: LEFT SIDE - BRANDING & ILLUSTRATION --- */}
        <div className="w-full md:w-[45%] p-16 flex flex-col items-center justify-center text-center">
          
          {/* Professional Logistics Illustration/Icon */}
          <div className="relative mb-12">
            <div className="absolute inset-0 bg-red-100 rounded-full blur-3xl opacity-50"></div>
            <div className="relative bg-white/70 p-6 rounded-full shadow-inner border border-red-100 text-7xl animate-bounce">
              🚛
            </div>
          </div>
          
          {/* Branded Motto/Headline */}
          <h2 className="text-4xl font-black uppercase italic tracking-tighter leading-none mb-6 text-slate-900">
            Connecting <span className="text-red-600">Trucks</span> & <span className="text-yellow-500">Freight</span> Instantly
          </h2>
          
          {/* Subtitle with key benefits */}
          <p className="text-sm font-bold text-slate-500 uppercase tracking-widest leading-loose">
            Unlock the most dynamic load board in logistics. Post, search, and secure bookings in one seamless interface.
          </p>
          
          {/* Trust badges/Icons */}
          <div className="flex gap-4 text-xs font-black uppercase text-slate-400 mt-12">
            <span>✓ Verified Carriers</span>
            <span>•</span>
            <span>✓ Real-time Updates</span>
          </div>
        </div>

        {/* --- UPDATE: RIGHT SIDE - LOGIN FORM INTEGRATED --- */}
        <div className="w-full md:w-[55%] bg-slate-50 p-16 flex items-center justify-center">
          
          {/* Form container - similar to your previous box design */}
          <form onSubmit={handleLogin} className="w-full max-w-md space-y-8 bg-white p-12 rounded-[2.5rem] shadow-lg border border-slate-100 relative">
            
            {/* Header with logo branding */}
            <div className="text-center">
              <div className="absolute top-[-2rem] left-[-2rem] bg-[#E11D48] text-white p-5 rounded-3xl shadow-xl text-3xl font-black tracking-tighter animate-pulse">
                TBP
              </div>
              <h1 className="text-3xl font-black italic uppercase text-red-600 leading-none mb-3">
                TRUCK BOARD <span className="text-slate-900">PRO</span>
              </h1>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest leading-loose">
                Your Professional Logistics Gateway
              </p>
              <div className="h-1 w-12 bg-slate-900 mx-auto mt-3 rounded-full"></div>
            </div>

            {/* Greeting section */}
            <div className="text-center">
               <h3 className="text-2xl font-black text-slate-800 uppercase leading-tight">Welcome Back</h3>
               <p className="text-sm font-bold text-slate-500 uppercase tracking-wide">Enter your details to access the load board</p>
            </div>

            {/* Input fields with validation feedback */}
            <div className="space-y-4">
              <input 
                type="email" 
                placeholder="Business Email" 
                className="w-full p-4 mb-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 ring-red-500 font-bold border border-slate-100 shadow-sm transition-all" 
                value={email} 
                onChange={e => setEmail(e.target.value)} 
                required 
              />
              <input 
                type="password" 
                placeholder="Your Password" 
                className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-2 ring-red-500 font-bold border border-slate-100 shadow-sm transition-all" 
                value={password} 
                onChange={e => setPassword(e.target.value)} 
                required 
              />
            </div>

            {/* Forgot password link and Login button */}
            <div className="text-center space-y-6">
               <a href="/forgot-password" className="text-xs font-bold text-red-600 uppercase hover:underline">Forgot password?</a>
               <button 
                type="submit"
                disabled={loading}
                className="w-full bg-[#E11D48] text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-slate-900 transition-all active:scale-95 shadow-lg shadow-red-200"
               >
                 {loading ? 'Entering...' : 'Enter Dashboard'}
               </button>
            </div>

            {/* Sign up prompt with updated style */}
            <div className="text-center mt-12 border-t border-slate-100 pt-8">
              <p className="text-sm font-bold text-slate-500 uppercase tracking-wide">Don't have an account yet?</p>
              <button 
                onClick={() => navigate('/signup')} 
                className="mt-3 text-red-600 font-black uppercase text-xs hover:underline"
              >
                 Request access / Sign Up Pro
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
